func (m trackMods) AddNewTrackLayouts(number int, mods ...TrackLayoutMod) TrackMod {
	return TrackModFunc(func(ctx context.Context, o *TrackTemplate) {
		related := o.f.NewTrackLayoutWithContext(ctx, mods...)
		m.AddTrackLayouts(number, related).Apply(ctx, o)
	})
}

func (m trackMods) AddExistingTrackLayouts(existingModels ...*models.TrackLayout) TrackMod {
	return TrackModFunc(func(ctx context.Context, o *TrackTemplate) {
		for _, em := range existingModels {
			o.r.TrackLayouts = append(o.r.TrackLayouts, &trackRTrackLayoutsR{
				o: o.f.FromExistingTrackLayout(em),
			})
		}
	})
}

func (m trackMods) WithoutTrackLayouts() TrackMod {
	return TrackModFunc(func(ctx context.Context, o *TrackTemplate) {
		o.r.TrackLayouts = nil
	})
}
